form:Form.form:Scripts:
		function ChangeHorario()
{
	var param = "<HORARIO id=\""+Ctrl("horario").GetXValue()+"\"/>";
	var Escuadras;	
	Escuadras=GetProxy().SQLService().GetOBJ(Ctrl("main").getResource("ESCUADRAS"),param);			
	Ctrl("oi_escuadra").setOptions(Escuadras.associatedELE);
	Ctrl("oi_escuadra").SetXValue("");
}

function load()
{ 
	if(Ctrl('empreq').GetEnabled() && Ctrl('empresa').GetXValue() == '')
	{
		alert('La Empresa es requerida');
		return false;
	}
	NomadTimeout("internal_load();",100,"Cargando la Lista..."); 
}

function loadadd() 
{ 
	if(Ctrl('empreq').GetEnabled() && Ctrl('empresa').GetXValue() == '')
	{
		alert('La Empresa es requerida');
		return false;
	}
	NomadTimeout("internal_loadadd();",100,"Agregando en la Lista..."); 
}

qry:select.qry:xquery:
			for $r in sql('
	SELECT 
		EMP.d_empresa, 
		LEG.oi_personal_emp, 
		LEG.e_numero_legajo, 
		PER.d_ape_y_nom,
		PER_TTA.e_nro_legajo_reloj,
		SEC.policy
	FROM 
		PER01_PERSONAL as PER, 
		PER02_PERSONAL_EMP as LEG, 
		TTA04_PERSONAL as PER_TTA,
		ORG03_EMPRESAS as EMP,
		NMD_SECURITY(class=\'NucleusRH.Base.Personal.LegajoEmpresa.PERSONAL_EMP\') as SEC
		{%?('##horario##'!='') {% , TTA04_HORARIOSPERS as HOR %} {% %} %}
	JOIN 
		PER.oi_personal INNER LEG.oi_personal,
		LEG.oi_empresa INNER EMP.oi_empresa,
		LEG.oi_personal_emp INNER PER_TTA.oi_personal_emp,
		LEG.oi_personal_emp LEFT OUTER SEC.id
		{%?('##horario##'!='') {% , HOR.oi_personal_emp INNER PER_TTA.oi_personal_emp %} {% %} %}
	WHERE 1=1
	{%?('##activos##'='1') {% and LEG.oi_indic_activo= \'1\' %} {% %} %}
	{%?('##empresa##'!='') {% and LEG.oi_empresa = ##empresa## %} {% %} %}
	{%?('##legajo_reloj_desde##'!='') {% and PER_TTA.e_nro_legajo_reloj >= ##legajo_reloj_desde## %} {% %} %}
	{%?('##legajo_reloj_hasta##'!='') {% and PER_TTA.e_nro_legajo_reloj <= ##legajo_reloj_hasta## %} {% %} %}
	{%?('##chksinreloj##'='1') {% and ISNULL(PER_TTA.e_nro_legajo_reloj) %} {% %} %}
	{%?('##tarjeta_desde##'!='') {% and PER_TTA.d_nro_tarjeta >= \'##tarjeta_desde##\' %} {% %} %}
	{%?('##tarjeta_hasta##'!='') {% and PER_TTA.d_nro_tarjeta <= \'##tarjeta_hasta##\' %} {% %} %}
	{%?('##chksintarjeta##'='1') {% and (PER_TTA.d_nro_tarjeta = \'\' or  ISNULL(PER_TTA.d_nro_tarjeta)) %} {% %} %}
	{%?('##grupo_horario##'!='') {% and PER_TTA.oi_grupo_hor = ##grupo_horario## %} {% %} %}
	{%?('##horario##'!='') 
		{% and (HOR.oi_horario=##horario##) 
			 and ((HOR.f_fechaInicio < {NOW()} 
			 AND HOR.f_fechaFin > {NOW()}) OR (HOR.f_fechaInicio < {NOW()} 
			 AND ISNULL(HOR.f_fechaFin)))
			 {%?('##oi_escuadra##'!='') 
			 	{% and (HOR.oi_escuadra=##oi_escuadra##) %} 
			 	{% %} 
			 %}
		%} 
		{% %} 
	%}			
	ORDER BY d_empresa ASC, e_numero_legajo ASC
')/ROWS/ROW
